//! Mirror of `distributed_inference::attention_closure_lift` (lines 109–215).
//! **Keep in sync** with `open-source/gnosis/distributed-inference/src/attention_closure_lift.rs`
//! when changing lift semantics — rtl-bridge avoids a heavy workspace dependency.

pub const TRITON_PHASE_COUNT: usize = 3;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ResolutionLiftAction {
    None,
    LiftResolution,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AttentionClosureState {
    pub heads: usize,
    pub coupling: usize,
    pub observer_resolution: usize,
    pub source_resolution: usize,
    pub unresolved_residue: usize,
    pub head_trace: Vec<usize>,
    pub trace_separated: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ResolutionLiftDecision {
    pub action: ResolutionLiftAction,
    pub after_observer_resolution: usize,
}

pub fn multi_head_phase_count(heads: usize) -> usize {
    TRITON_PHASE_COUNT * heads
}

pub fn attention_head_phase(head: usize) -> usize {
    TRITON_PHASE_COUNT * (head + 1)
}

pub fn attention_head_coordinate_at_resolution(head: usize, resolution: usize) -> usize {
    attention_head_phase(head) % resolution.max(1)
}

pub fn n_head_coordinate_trace(heads: usize, resolution: usize) -> Vec<usize> {
    (0..heads)
        .map(|head| attention_head_coordinate_at_resolution(head, resolution))
        .collect()
}

pub fn trace_separated(trace: &[usize]) -> bool {
    for i in 0..trace.len() {
        for j in (i + 1)..trace.len() {
            if trace[i] == trace[j] {
                return false;
            }
        }
    }
    true
}

pub fn attention_closure_state(
    heads: usize,
    coupling: usize,
    observer_resolution: usize,
) -> AttentionClosureState {
    let observer_resolution = observer_resolution.max(1);
    let source_resolution = multi_head_phase_count(heads) + coupling;
    let unresolved_residue = source_resolution.saturating_sub(observer_resolution);
    let head_trace = n_head_coordinate_trace(heads, observer_resolution);
    let separated = trace_separated(&head_trace);

    AttentionClosureState {
        heads,
        coupling,
        observer_resolution,
        source_resolution,
        unresolved_residue,
        head_trace,
        trace_separated: separated,
    }
}

pub fn apply_dark_deceptacon_resolution_lift(
    state: AttentionClosureState,
    residue_threshold: usize,
) -> ResolutionLiftDecision {
    let threshold = residue_threshold.max(1);
    let should_lift = !state.trace_separated || state.unresolved_residue >= threshold;
    if !should_lift {
        return ResolutionLiftDecision {
            action: ResolutionLiftAction::None,
            after_observer_resolution: state.observer_resolution,
        };
    }

    let after = attention_closure_state(state.heads, state.coupling, state.source_resolution);

    ResolutionLiftDecision {
        action: ResolutionLiftAction::LiftResolution,
        after_observer_resolution: after.observer_resolution,
    }
}
